bool balanced(const std::string& expr) {
    std::stack<char> s;
    for (char c : expr) {
        if (c == '(' || c == '[') s.push(c);
        else if (c == ')' || c == ']') {
            if (s.empty()) return false;
            s.pop();
        }
    }
    return s.empty();
}

